head.b:skin:
:root{--gold:#D4AF37;--gold-light:#E8C84A;--gold-dark:#B8960C;--dark:#1a1a1a;--dark-bg:#111;--dark-card:#1e1e1e;--dark-border:#2a2a2a;--text:#e0e0e0;--text-muted:#999}
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Noto Sans KR',sans-serif;background:var(--dark-bg);color:var(--text);line-height:1.8}
a{color:var(--gold);text-decoration:none;transition:color .3s}
a:hover{color:var(--gold-light)}
h1,h2,h3,h4{font-family:'Noto Serif KR',serif;color:#fff}
img{max-width:100%;height:auto}
::selection{background:var(--gold);color:var(--dark)}
::-webkit-scrollbar{width:8px}
::-webkit-scrollbar-track{background:var(--dark-bg)}
::-webkit-scrollbar-thumb{background:var(--gold-dark);border-radius:4px}

.top-bar{background:var(--dark);border-bottom:1px solid var(--dark-border);padding:8px 0;font-size:13px;color:var(--text-muted)}
.top-bar .container{max-width:1152px;margin:0 auto;padding:0 16px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px}
.top-bar a{color:var(--text-muted)}
.top-bar a:hover{color:var(--gold)}
.top-bar-item{display:flex;align-items:center;gap:6px}

.site-header{background:var(--dark);border-bottom:1px solid var(--dark-border);position:sticky;top:0;z-index:50}
.header-inner{max-width:1152px;margin:0 auto;padding:0 16px;display:flex;align-items:center;justify-content:space-between;height:64px}
.logo{display:flex;align-items:center;gap:12px}
.logo-icon{width:40px;height:40px;background:linear-gradient(135deg,var(--gold),var(--gold-dark));border-radius:8px;display:flex;align-items:center;justify-content:center;font-weight:700;color:var(--dark);font-size:18px}
.logo-text{display:flex;flex-direction:column}
.logo-title{font-family:'Noto Serif KR',serif;font-size:18px;font-weight:700;color:var(--gold);line-height:1.2}
.logo-subtitle{font-size:11px;color:var(--text-muted);letter-spacing:1px}
.main-nav{display:flex;align-items:center;gap:24px}
.main-nav a{color:var(--text);font-size:14px;font-weight:500;padding:8px 0;border-bottom:2px solid transparent;transition:all .3s}
.main-nav a:hover{color:var(--gold);border-bottom-color:var(--gold)}

.site-container{max-width:1152px;margin:0 auto;padding:32px 16px;display:grid;grid-template-columns:1fr 300px;gap:32px}

/* Post list styling */
.date-header span{display:none}
.post{background:var(--dark-card);border:1px solid var(--dark-border);border-radius:12px;padding:24px;margin-bottom:24px;transition:all .3s}
.post:hover{border-color:rgba(212,175,55,0.4)}
.post-title,.post h3.post-title{font-family:'Noto Serif KR',serif;font-size:20px;font-weight:600;color:#fff;margin-bottom:12px;line-height:1.4}
.post-title a,.post h3 a{color:#fff;transition:color .3s}
.post-title a:hover,.post h3 a:hover{color:var(--gold)}
.post-header-line-1{font-size:13px;color:var(--text-muted);margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid var(--dark-border)}
.post-body{font-size:15px;line-height:1.8;color:var(--text)}
.post-body img{border-radius:8px;margin:16px 0}
.post-body h2{font-size:1.5rem;font-weight:600;color:var(--gold);margin:32px 0 16px}
.post-body h3{font-size:1.25rem;font-weight:600;color:#fff;margin:24px 0 12px}
.post-body p{margin-bottom:16px}
.post-body blockquote{border-left:3px solid var(--gold);padding-left:16px;margin:16px 0;color:#aaa;font-style:italic}
.post-body ul,.post-body ol{padding-left:24px;margin-bottom:16px}
.post-body a{color:var(--gold);text-decoration:underline}
.post-footer{margin-top:16px;padding-top:12px;border-top:1px solid var(--dark-border);font-size:13px;color:var(--text-muted)}
.post-footer .post-labels a{font-size:11px;padding:2px 8px;border-radius:9999px;background:rgba(212,175,55,0.1);color:var(--gold);border:1px solid rgba(212,175,55,0.2);margin-right:4px}

/* Pagination */
.blog-pager{display:flex;justify-content:center;gap:16px;margin-top:32px;padding-top:24px}
.blog-pager a{padding:8px 20px;border-radius:8px;background:var(--dark-card);border:1px solid var(--dark-border);color:var(--text-muted);font-size:14px;transition:all .3s}
.blog-pager a:hover{border-color:var(--gold);color:var(--gold)}
#blog-pager{display:flex;justify-content:center;gap:16px;margin-top:32px}
#blog-pager a{padding:8px 20px;border-radius:8px;background:var(--dark-card);border:1px solid var(--dark-border);color:var(--text-muted);font-size:14px;transition:all .3s}
#blog-pager a:hover{border-color:var(--gold);color:var(--gold)}

/* Sidebar */
.sidebar .widget{background:var(--dark-card);border:1px solid var(--dark-border);border-radius:12px;padding:20px;margin-bottom:24px}
.sidebar .widget h2,.sidebar .widget h3{font-family:'Noto Serif KR',serif;font-size:16px;font-weight:600;color:#fff;margin-bottom:16px;padding-bottom:12px;border-bottom:1px solid var(--dark-border)}
.sidebar .widget ul{list-style:none;padding:0;margin:0}
.sidebar .widget li{margin-bottom:4px}
.sidebar .widget li a{display:block;padding:6px 12px;border-radius:8px;color:var(--text-muted);font-size:14px;transition:all .3s}
.sidebar .widget li a:hover{background:rgba(212,175,55,0.1);color:var(--gold)}
.widget-content{font-size:14px;color:var(--text-muted)}
.store-info-item{display:flex;align-items:flex-start;gap:10px;padding:10px 0;border-bottom:1px solid var(--dark-border);color:var(--text-muted)}
.store-info-item:last-child{border-bottom:none}
.store-info-icon{color:var(--gold);flex-shrink:0}
.store-info-label{font-size:12px;color:var(--text-muted);margin-bottom:2px}
.store-info-value{color:var(--text);font-weight:500}

/* Label cloud */
.cloud-label-widget-content{display:flex;flex-wrap:wrap;gap:6px}
.cloud-label-widget-content a{font-size:12px!important;padding:4px 12px;border-radius:9999px;background:rgba(212,175,55,0.1);color:var(--gold)!important;border:1px solid rgba(212,175,55,0.2);transition:all .3s}
.cloud-label-widget-content a:hover{background:rgba(212,175,55,0.2)}

/* Comments */
.comments-section,.comment-thread{background:var(--dark-card);border:1px solid var(--dark-border);border-radius:12px;padding:24px;margin-top:24px}
#comments{color:var(--text)}
#comments .comment-author{color:var(--gold);font-weight:600}
#comments .comment-body{color:var(--text);font-size:14px}
.comment-form textarea,.comment-form input{background:var(--dark);border:1px solid var(--dark-border);border-radius:8px;padding:8px 12px;color:var(--text);font-family:'Noto Sans KR',sans-serif}
.comment-form textarea:focus,.comment-form input:focus{outline:none;border-color:var(--gold)}

/* Search */
.search-box input,.widget .search-input{background:var(--dark);border:1px solid var(--dark-border);border-radius:8px;padding:8px 12px;color:var(--text);font-size:14px;width:100%}
.search-box input:focus,.widget .search-input:focus{outline:none;border-color:var(--gold)}
.search-box button,.widget .search-action{padding:8px 16px;background:var(--gold);color:var(--dark);border:none;border-radius:8px;font-weight:600;cursor:pointer}

/* Footer */
.site-footer{border-top:1px solid var(--dark-border);background:var(--dark);margin-top:48px}
.footer-inner{max-width:1152px;margin:0 auto;padding:48px 16px;display:grid;grid-template-columns:repeat(3,1fr);gap:32px}
.footer-section h4{font-family:'Noto Serif KR',serif;font-size:16px;font-weight:600;color:#fff;margin-bottom:16px}
.footer-section p,.footer-section a{font-size:14px;color:var(--text-muted);line-height:1.8}
.footer-brand-name{color:var(--gold);font-family:'Noto Serif KR',serif;font-size:18px;font-weight:700;margin-bottom:12px}
.footer-categories{list-style:none}
.footer-categories li{margin-bottom:6px}
.footer-categories a{color:var(--text-muted)}
.footer-categories a:hover{color:var(--gold)}
.footer-bottom{max-width:1152px;margin:0 auto;padding:20px 16px;border-top:1px solid var(--dark-border);text-align:center;font-size:13px;color:var(--text-muted)}

/* Hide blogger defaults */
.post-share-buttons{display:none}
.post-footer-line{display:none}
.feed-links{display:none}
.post-comment-link{display:none}
.post-icons{display:none}
.widget .post-count{display:none}

.mobile-menu-btn{display:none;align-items:center;justify-content:center;width:36px;height:36px;background:none;border:1px solid var(--dark-border);border-radius:8px;color:var(--text);cursor:pointer;font-size:20px}

@media(max-width:768px){
  .top-bar{display:none}
  .main-nav{display:none}
  .site-container{grid-template-columns:1fr}
  .footer-inner{grid-template-columns:1fr}
  .header-inner{height:56px}
  .logo-title{font-size:15px}
  .mobile-menu-btn{display:flex!important}
}
.main-nav.show-mobile{display:flex!important;flex-direction:column;position:fixed;top:56px;left:0;right:0;background:var(--dark);border-bottom:1px solid var(--dark-border);padding:16px;z-index:49;gap:0}
.main-nav.show-mobile a{padding:12px 16px;border-bottom:none;border-radius:8px}
.main-nav.show-mobile a:hover{background:rgba(212,175,55,0.1)}
